//! Per-layer aggregation for standing-wave metrics (`zed-metrics-sink`).
//!
//! Keeps commutative gestalt folds aligned with [`crate::standing_wave_metrics_format::MetricsRecord`]
//! wire bytes and `bitwise::frf_witness`.

use std::collections::BTreeMap;
use std::io::{BufRead, Read};

use bitwise::frf_witness;
use serde::Deserialize;

use crate::standing_wave_metrics_format::{MetricsRecord, RECORD_SIZE};

/// Rolling aggregate for one `layer_idx`.
#[derive(Debug)]
pub struct LayerAgg {
    pub samples: usize,
    pub sum_coverage: f64,
    pub sum_speedup: f64,
    pub min_coverage: f64,
    pub max_coverage: f64,
    pub sum_saved_bytes: u64,
    pub hidden_dim: u32,
    /// XOR-fold of per-sample wire XOR parity (order-independent across samples).
    pub gestalt_xor_parity_fold: u8,
    /// Triadic fold of per-sample `gestalt_triad_mod3_wire`.
    pub gestalt_triad_mod3_fold: u8,
}

impl LayerAgg {
    /// Builds an empty aggregate (`min_coverage` starts at `+∞` until first sample).
    pub fn new() -> Self {
        Self {
            samples: 0,
            sum_coverage: 0.0,
            sum_speedup: 0.0,
            min_coverage: f64::INFINITY,
            max_coverage: f64::NEG_INFINITY,
            sum_saved_bytes: 0,
            hidden_dim: 0,
            gestalt_xor_parity_fold: 0,
            gestalt_triad_mod3_fold: 0,
        }
    }

    /// Absorb one metrics row.
    pub fn observe_record(&mut self, rec: &MetricsRecord) {
        self.samples += 1;
        self.sum_coverage += rec.coverage as f64;
        self.sum_speedup += rec.speedup as f64;
        self.sum_saved_bytes += rec.saved_bytes;
        let cov = rec.coverage as f64;
        self.min_coverage = self.min_coverage.min(cov);
        self.max_coverage = self.max_coverage.max(cov);
        if rec.hidden_dim > 0 {
            self.hidden_dim = rec.hidden_dim;
        }
        self.gestalt_xor_parity_fold ^= rec.gestalt_xor_parity_wire();
        if let Some(d) =
            frf_witness::triad_add_fin3(self.gestalt_triad_mod3_fold, rec.gestalt_triad_mod3_wire())
        {
            self.gestalt_triad_mod3_fold = d;
        }
    }
}

impl Default for LayerAgg {
    fn default() -> Self {
        Self::new()
    }
}

/// Fold per-layer gestalt summaries into globals (order across layers is irrelevant — XOR / ℤ/3ℤ add).
pub fn global_gestalt_folds(by_layer: &BTreeMap<u32, LayerAgg>) -> (u8, u8) {
    let mut xor_acc = 0u8;
    let mut triad_acc = 0u8;
    for agg in by_layer.values() {
        xor_acc ^= agg.gestalt_xor_parity_fold;
        if let Some(d) = frf_witness::triad_add_fin3(triad_acc, agg.gestalt_triad_mod3_fold) {
            triad_acc = d;
        }
    }
    (xor_acc, triad_acc)
}

/// XOR-fold gestalt parity across individual rows (reference for tests).
pub fn naive_global_xor_parity_fold(records: &[MetricsRecord]) -> u8 {
    records
        .iter()
        .fold(0u8, |acc, rec| acc ^ rec.gestalt_xor_parity_wire())
}

/// Triadic fold across individual rows (reference for tests).
pub fn naive_global_triad_mod3_fold(records: &[MetricsRecord]) -> u8 {
    records.iter().fold(0u8, |acc, rec| {
        frf_witness::triad_add_fin3(acc, rec.gestalt_triad_mod3_wire()).unwrap_or(acc)
    })
}

/// Merge streaming records into `by_layer`.
pub fn aggregate_records<I>(by_layer: &mut BTreeMap<u32, LayerAgg>, records: I)
where
    I: IntoIterator<Item = MetricsRecord>,
{
    for rec in records {
        let agg = by_layer.entry(rec.layer_idx).or_default();
        agg.observe_record(&rec);
    }
}

/// Read concatenated `RECORD_SIZE` BWMR blobs from `r`.
///
/// Returns `(total_good_records, bad_fragments)` — a trailing partial record counts as one bad fragment.
pub fn ingest_binary<R: Read>(
    mut r: R,
    by_layer: &mut BTreeMap<u32, LayerAgg>,
) -> std::io::Result<(usize, usize)> {
    let mut buf = [0u8; RECORD_SIZE];
    let mut total_rows = 0usize;
    let mut bad_rows = 0usize;
    loop {
        let mut filled = 0usize;
        while filled < RECORD_SIZE {
            match r.read(&mut buf[filled..])? {
                0 => break,
                n => filled += n,
            }
        }
        if filled == 0 {
            break;
        }
        if filled < RECORD_SIZE {
            bad_rows += 1;
            break;
        }
        match MetricsRecord::from_bytes(&buf) {
            Some(rec) => {
                let agg = by_layer.entry(rec.layer_idx).or_default();
                agg.observe_record(&rec);
                total_rows += 1;
            }
            None => {
                bad_rows += 1;
            }
        }
    }
    Ok((total_rows, bad_rows))
}

/// One JSON line matching [`MetricsRecord::to_json_line`] field set.
#[derive(Debug, Deserialize)]
pub struct MetricsJsonLine {
    pub ts: u64,
    pub token_step: u32,
    pub layer_idx: u32,
    pub hidden_dim: u32,
    pub standing_count: u32,
    pub coverage: f32,
    pub speedup: f32,
    pub original_bytes: u64,
    pub compressed_bytes: u64,
    pub saved_bytes: u64,
    pub forward_ms: u64,
}

impl From<MetricsJsonLine> for MetricsRecord {
    fn from(row: MetricsJsonLine) -> Self {
        MetricsRecord {
            ts: row.ts,
            token_step: row.token_step,
            layer_idx: row.layer_idx,
            hidden_dim: row.hidden_dim,
            standing_count: row.standing_count,
            coverage: row.coverage,
            speedup: row.speedup,
            original_bytes: row.original_bytes,
            compressed_bytes: row.compressed_bytes,
            saved_bytes: row.saved_bytes,
            forward_ms: row.forward_ms,
        }
    }
}

/// Parse JSONL (one object per line). Non-object lines are skipped without counting as bad.
///
/// Malformed JSON objects increment `bad_rows`.
pub fn ingest_jsonl<B: BufRead>(
    reader: B,
    by_layer: &mut BTreeMap<u32, LayerAgg>,
) -> (usize, usize) {
    let mut total_rows = 0usize;
    let mut bad_rows = 0usize;
    for line in reader.lines() {
        let line = match line {
            Ok(l) => l,
            Err(_) => {
                bad_rows += 1;
                continue;
            }
        };
        let trimmed = line.trim();
        if trimmed.is_empty() || !trimmed.starts_with('{') {
            continue;
        }
        let row: MetricsJsonLine = match serde_json::from_str(trimmed) {
            Ok(r) => r,
            Err(_) => {
                bad_rows += 1;
                continue;
            }
        };
        let rec = MetricsRecord::from(row);
        let agg = by_layer.entry(rec.layer_idx).or_default();
        agg.observe_record(&rec);
        total_rows += 1;
    }
    (total_rows, bad_rows)
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::io::Cursor;

    fn sample_rec(layer: u32, ts: u64, saved: u64, cov: f32) -> MetricsRecord {
        MetricsRecord {
            ts,
            token_step: 1,
            layer_idx: layer,
            hidden_dim: 4096,
            standing_count: 100,
            coverage: cov,
            speedup: 2.0,
            original_bytes: 1000,
            compressed_bytes: 500,
            saved_bytes: saved,
            forward_ms: 10,
        }
    }

    #[test]
    fn layer_agg_sample_mean_and_min_max() {
        let mut agg = LayerAgg::new();
        agg.observe_record(&sample_rec(0, 1, 100, 0.25));
        agg.observe_record(&sample_rec(0, 2, 300, 0.75));
        assert_eq!(agg.samples, 2);
        assert_eq!(agg.sum_saved_bytes, 400);
        assert!((agg.sum_coverage / 2.0 - 0.5).abs() < 1e-9);
        assert!((agg.min_coverage - 0.25).abs() < 1e-9);
        assert!((agg.max_coverage - 0.75).abs() < 1e-9);
        assert_eq!(agg.hidden_dim, 4096);
    }

    #[test]
    fn reorder_within_layer_commutes_gestalt_and_scalar_sums() {
        let a = sample_rec(0, 1, 10, 0.1);
        let b = sample_rec(0, 2, 20, 0.2);
        let mut m1 = BTreeMap::new();
        aggregate_records(&mut m1, [a, b]);
        let mut m2 = BTreeMap::new();
        aggregate_records(&mut m2, [b, a]);
        assert_eq!(
            m1[&0].gestalt_xor_parity_fold,
            m2[&0].gestalt_xor_parity_fold
        );
        assert_eq!(
            m1[&0].gestalt_triad_mod3_fold,
            m2[&0].gestalt_triad_mod3_fold
        );
        assert_eq!(m1[&0].sum_saved_bytes, m2[&0].sum_saved_bytes);
        assert_eq!(m1[&0].samples, m2[&0].samples);
    }

    #[test]
    fn global_folds_match_naive_over_flat_record_list() {
        let recs = vec![
            sample_rec(0, 1, 100, 0.3),
            sample_rec(1, 2, 200, 0.4),
            sample_rec(0, 3, 50, 0.5),
        ];
        let mut by_layer = BTreeMap::new();
        aggregate_records(&mut by_layer, recs.clone());
        let (gx, gt) = global_gestalt_folds(&by_layer);
        assert_eq!(gx, naive_global_xor_parity_fold(&recs));
        assert_eq!(gt, naive_global_triad_mod3_fold(&recs));
    }

    #[test]
    fn combined_layer_xor_equals_xor_of_row_parities() {
        let recs = vec![sample_rec(0, 1, 1, 0.1), sample_rec(0, 2, 2, 0.2)];
        let mut by_layer = BTreeMap::new();
        aggregate_records(&mut by_layer, recs.clone());
        let layer_xor = by_layer[&0].gestalt_xor_parity_fold;
        let naive = naive_global_xor_parity_fold(&recs);
        assert_eq!(layer_xor, naive);
    }

    #[test]
    fn ingest_binary_matches_aggregate_records() {
        let recs = vec![sample_rec(0, 1, 11, 0.11), sample_rec(1, 2, 22, 0.22)];
        let mut blob = Vec::<u8>::new();
        for r in &recs {
            blob.extend_from_slice(&r.to_bytes());
        }
        let mut from_reader = BTreeMap::new();
        let (good, bad) = ingest_binary(Cursor::new(blob), &mut from_reader).unwrap();
        assert_eq!(good, 2);
        assert_eq!(bad, 0);

        let mut direct = BTreeMap::new();
        aggregate_records(&mut direct, recs.clone());
        assert_eq!(from_reader[&0].samples, direct[&0].samples);
        assert_eq!(
            from_reader[&0].gestalt_xor_parity_fold,
            direct[&0].gestalt_xor_parity_fold
        );
        assert_eq!(
            from_reader[&1].gestalt_triad_mod3_fold,
            direct[&1].gestalt_triad_mod3_fold
        );
    }

    #[test]
    fn ingest_binary_partial_tail_counts_bad() {
        let rec = sample_rec(2, 9, 9, 0.9);
        let mut blob = rec.to_bytes().to_vec();
        blob.truncate(RECORD_SIZE / 2);
        let mut m = BTreeMap::new();
        let (good, bad) = ingest_binary(Cursor::new(blob), &mut m).unwrap();
        assert_eq!(good, 0);
        assert_eq!(bad, 1);
        assert!(m.is_empty());
    }

    #[test]
    fn ingest_binary_bad_magic_counts_bad_not_total() {
        let mut blob = vec![0u8; RECORD_SIZE];
        blob[0..4].copy_from_slice(b"XXXX");
        let mut m = BTreeMap::new();
        let (good, bad) = ingest_binary(Cursor::new(blob), &mut m).unwrap();
        assert_eq!(good, 0);
        assert_eq!(bad, 1);
    }

    #[test]
    fn json_round_trip_line_matches_binary_gestalt() {
        let rec = sample_rec(5, 123, 999, 0.12345);
        let line = rec.to_json_line();
        let trimmed = line.trim();
        let parsed: MetricsJsonLine = serde_json::from_str(trimmed).unwrap();
        let back: MetricsRecord = parsed.into();
        assert_eq!(
            back.gestalt_xor_parity_wire(),
            rec.gestalt_xor_parity_wire()
        );
        assert_eq!(
            back.gestalt_triad_mod3_wire(),
            rec.gestalt_triad_mod3_wire()
        );

        let mut m = BTreeMap::new();
        let (total, bad) = ingest_jsonl(Cursor::new(line.as_bytes()), &mut m);
        assert_eq!(bad, 0);
        assert_eq!(total, 1);
        assert_eq!(m[&5].samples, 1);
        assert_eq!(m[&5].gestalt_xor_parity_fold, rec.gestalt_xor_parity_wire());
    }

    #[test]
    fn jsonl_partial_object_is_bad_row() {
        let junk = "{\"layer_idx\":1,\"coverage\":0.5}\n";
        let mut m = BTreeMap::new();
        let (total, bad) = ingest_jsonl(Cursor::new(junk.as_bytes()), &mut m);
        assert_eq!(total, 0);
        assert_eq!(bad, 1);
        assert!(m.is_empty());
    }

    #[test]
    fn jsonl_skips_blank_and_non_json_lines_without_bad() {
        let s = "\n  \nnot json\n{\"ts\":1,\"token_step\":2,\"layer_idx\":3,\"hidden_dim\":4,\"standing_count\":5,\"coverage\":0.5,\"speedup\":2.0,\"original_bytes\":16,\"compressed_bytes\":8,\"saved_bytes\":8,\"forward_ms\":99}\n";
        let mut m = BTreeMap::new();
        let (total, bad) = ingest_jsonl(Cursor::new(s.as_bytes()), &mut m);
        assert_eq!(bad, 0);
        assert_eq!(total, 1);
        assert_eq!(m[&3].samples, 1);
    }

    #[test]
    fn multi_record_jsonl_matches_binary_blob_for_same_records() {
        let recs = vec![
            sample_rec(0, 1, 100, 0.10),
            sample_rec(1, 2, 200, 0.20),
            sample_rec(0, 3, 150, 0.30),
        ];
        let mut bin = Vec::<u8>::new();
        let mut jsonl = String::new();
        for r in &recs {
            bin.extend_from_slice(&r.to_bytes());
            jsonl.push_str(&r.to_json_line());
        }
        let mut from_bin = BTreeMap::new();
        ingest_binary(Cursor::new(bin), &mut from_bin).unwrap();
        let mut from_json = BTreeMap::new();
        ingest_jsonl(Cursor::new(jsonl.as_bytes()), &mut from_json);
        assert_eq!(from_bin.len(), from_json.len());
        for k in from_bin.keys() {
            assert_eq!(
                from_bin[k].gestalt_xor_parity_fold, from_json[k].gestalt_xor_parity_fold,
                "layer {}",
                k
            );
            assert_eq!(
                from_bin[k].gestalt_triad_mod3_fold, from_json[k].gestalt_triad_mod3_fold,
                "layer {}",
                k
            );
            assert_eq!(from_bin[k].samples, from_json[k].samples);
        }
    }

    #[test]
    fn hidden_dim_zero_does_not_overwrite_prior_nonzero() {
        let mut z = sample_rec(0, 1, 1, 0.1);
        z.hidden_dim = 4096;
        let mut z2 = sample_rec(0, 2, 2, 0.2);
        z2.hidden_dim = 0;
        let mut m = BTreeMap::new();
        aggregate_records(&mut m, [z, z2]);
        assert_eq!(m[&0].hidden_dim, 4096);
    }

    #[test]
    fn zero_records_global_fold_is_neutral() {
        let m: BTreeMap<u32, LayerAgg> = BTreeMap::new();
        assert_eq!(global_gestalt_folds(&m), (0, 0));
    }
}
